script:
frappe.ui.form.on("BOM", {
    custom_item_template: async function (frm) {
        if (!frm.doc.custom_item_template) return;

        // 1️⃣ Fetch template
        let template = await frappe.call({
            method: "frappe.client.get",
            args: {
                doctype: "Raw Material Template",
                name: frm.doc.custom_item_template,
            },
        });

        if (!template.message) return;

        frm.clear_table("items");

        // 2️⃣ SEQUENTIAL processing (fixes missing UOM/rate)
        for (const tpl of template.message.items || []) {
            let row = frm.add_child("items");
            row.item_code = tpl.item_code;
            row.qty = tpl.qty || 1;

            // 3️⃣ Fetch ERPNext standard item details — sequential & stable
            let resp = await frappe.call({
                method: "erpnext.manufacturing.doctype.bom.bom.get_item_details",
                args: {
                    item_code: row.item_code,
                    bom_no: frm.doc.name || "",
                    company: frm.doc.company,
                    qty: row.qty,
                },
            });

            if (resp.message) {
                frappe.model.set_value(row.doctype, row.name, {
                    item_name: resp.message.item_name,
                    description: resp.message.description,
                    stock_uom: resp.message.stock_uom,
                    uom: resp.message.uom,
                    conversion_factor: resp.message.conversion_factor,
                    rate: resp.message.rate,
                    amount: resp.message.amount,
                });
            }

            // 4️⃣ Trigger ERPNext built-in logic for this row (but ONLY once)
            await frm.script_manager.trigger("item_code", row.doctype, row.name);
        }

        frm.refresh_field("items");
    }
});

frappe.ui.form.on('Opportunity Item', {
    item_code(frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        if (!row.item_code) return;

        // Always use Standard Selling price list
        const PRICE_LIST = "Standard Selling";
        
        // Prevent overwrite if user edits rate
        if (row.rate && row.rate > 0) return;
        
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "Item Price",
                filters: {
                    item_code: row.item_code,
                    price_list: PRICE_LIST,
                    selling: 1
                },
                fieldname: ["price_list_rate"]
            },
            callback(r) {
                if (r.message && r.message.price_list_rate) {
                    frappe.model.set_value(
                        cdt,
                        cdn,
                        "rate",
                        r.message.price_list_rate
                    );
                }
            }
        });
    }
});
